model Conclusion {
  id             String @id @default(cuid())
  organizationId String

  /// Stable id if synced from / produced for Noosphere
  noosphereId String? @unique
  text        String

  // ── Dedup key ──────────────────────────────────────────────────────
  // `normalizedText` is `LOWER(TRIM(REGEXP_REPLACE(text, '\s+', ' ')))`
  // computed once at ingest time. The ingest pipeline checks for an
  // existing Conclusion in the same org with a matching normalizedText;
  // if one exists, it adds the current upload as an ADDITIONAL source
  // via ConclusionSource rather than inserting a duplicate row. That's
  // what makes deletion correct: when two uploads produced the same
  // claim and we delete one, the conclusion stays — it's still
  // supported by the other source.
  //
  // Nullable so the column can be added to an existing DB without a
  // rewrite; the migration back-fills every existing row. Indexed
  // `(organizationId, normalizedText)` because every lookup is scoped
  // to a single org.
  normalizedText         String?
  confidenceTier         String // firm | founder | open (ConfidenceTier)
  rationale              String   @default("")
  supportingPrincipleIds String   @default("[]") // JSON string[]
  evidenceChainClaimIds  String   @default("[]")
  dissentClaimIds        String   @default("[]")
  confidence             Float    @default(0)
  topicHint              String   @default("") // UI filter / display
  createdAt              DateTime @default(now())

  /// JSON-serialized float[] embedding produced by Noosphere's sentence
  /// encoder at ingest time. Null for conclusions ingested before this
  /// column was added; the semantic explorer backfills on demand.
  embeddingJson String?

  attributedFounderId     String?
  attributedFounder       Founder?                    @relation("ConclusionFounder", fields: [attributedFounderId], references: [id])
  organization            Organization                @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  publicationReviews      PublicationReview[]
  sources                 ConclusionSource[]
  methodologyProfiles     MethodologyProfile[]
  /// Optional MQS row (1:1). Built by `noosphere mqs backfill`; re-runnable
  /// without rewriting the underlying methodology profile.
  methodologyQualityScore MethodologyQualityScore?
  conclusionMethods       ConclusionMethod[]
  domainBoundVerdicts     DomainBoundVerdict[]
  recalibrationOverride   RecalibrationOverride?
  deletionRequests        ConclusionDeletionRequest[]
  dashboardDismissals     DashboardDismissal[]

  /// Conclusion edit timestamp; the public MQS pill is only shown when the
  /// MQS row's `scoredAt` is at least this recent.
  updatedAt DateTime? @updatedAt

  @@index([organizationId])
  @@index([organizationId, normalizedText])
}

/// Many-to-many bridge Conclusion ↔ Upload.
///
/// Every conclusion that came out of the ingest pipeline has at least
/// one row here tying it back to the upload it was extracted from.
/// When the SAME normalized text appears in multiple uploads, the
/// ingest pipeline reuses the existing Conclusion row and adds a new
/// ConclusionSource row per additional upload, so the upstream count
/// can drop from 2 → 1 → 0 as uploads are deleted.
///
/// Delete semantics (enforced by the app-side delete handlers, NOT by
/// FK cascade — we soft-delete uploads, so the FK's ON DELETE CASCADE
/// would not fire anyway):
///
///   * When an upload is soft-deleted, every ConclusionSource row
///     with that uploadId is hard-deleted.
///   * After that, any Conclusion with zero remaining rows is
///     hard-deleted too (the claim's last source is gone).
///   * Conclusions with sources from other uploads remain, just
///     with one fewer row.
///
/// The FK cascade below still serves as a safety net for the rare
/// case of a hard-delete (org takedown, privacy-law purge).
model ConclusionSource {
  conclusionId String
  uploadId     String
  createdAt    DateTime @default(now())

  conclusion Conclusion @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  upload     Upload     @relation(fields: [uploadId], references: [id], onDelete: Cascade)

  @@id([conclusionId, uploadId])
  @@index([conclusionId])
  @@index([uploadId])
}

// ── Publication (SP10) — review queue + versioned public snapshots ───────────

/// Internal gate before a conclusion may appear on the public site.
model PublicationReview {
  id             String @id @default(cuid())
  organizationId String
  conclusionId   String

  /// queued | in_review | needs_revision | declined | published
  status        String @default("queued")
  /// JSON: { metaAnalysisOk, adversarialEngagedOk, clarityOk, noLeakageOk }
  checklistJson String @default("{}")
  reviewerNotes String @default("")
  declineReason String @default("")
  revisionAsk   String @default("")

  reviewerFounderId String?
  createdAt         DateTime @default(now())
  updatedAt         DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  target       Conclusion   @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  reviewer     Founder?     @relation("PublicationReviewer", fields: [reviewerFounderId], references: [id])

  @@index([organizationId])
  @@index([conclusionId])
  @@index([status])
}

/// Immutable-ish public snapshot (new row per material revision).
model PublishedConclusion {
  id                 String @id @default(cuid())
  organizationId     String
  sourceConclusionId String

model Organization {
  id        String    @id @default(cuid())
  /// URL-safe tenant key (login, subdomains, worker routing)
  slug      String    @unique
  name      String
  /// Soft-delete grace window (hard-delete after policy window)
  deletedAt DateTime?
  createdAt DateTime  @default(now())
  updatedAt DateTime  @updatedAt

  founders                 Founder[]
  sessions                 Session[]
  uploads                  Upload[]
  conclusions              Conclusion[]
  contradictions           Contradiction[]
  driftEvents              DriftEvent[]
  researchSuggestions      ResearchSuggestion[]
  reviewItems              ReviewItem[]
  openQuestions            OpenQuestion[]
  auditEvents              AuditEvent[]
  publicationReviews       PublicationReview[]
  publishedConclusions     PublishedConclusion[]
  publicResponses          PublicResponse[]
  responseTriages          ResponseTriage[]
  publicReplies            PublicReply[]
  apiKeys                  ApiKey[]
  currentEvents            CurrentEvent[]
  eventOpinions            EventOpinion[]
  methodologyProfiles      MethodologyProfile[]
  methodologyQualityScores MethodologyQualityScore[]
  socialPosts              SocialPost[]
  operatorStates           OperatorState[]
  forecastMarkets          ForecastMarket[]
  forecastPredictions      ForecastPrediction[]
  forecastTraces           ForecastTrace[]
  forecastBets             ForecastBet[]
  forecastPortfolios       ForecastPortfolioState[]
  watchedMarkets           WatchedMarket[]
  conclusionMethods        ConclusionMethod[]
  methodTrackRecords       MethodTrackRecord[]
  anchorRevisions          AnchorRevision[]
  domainBoundVerdicts      DomainBoundVerdict[]
  calibrationModels        CalibrationModel[]
  recalibrationOverrides   RecalibrationOverride[]
  revisionEvents           RevisionEvent[]
  sourceStandings          SourceStanding[]
  sourceTriageItems        SourceTriageItem[]
  sourceCredibility        SourceCredibilityUpdate[]
  citationVerdicts         CitationVerdict[]
  attentionActions         AttentionAction[]
  subscribers              Subscriber[]
}

// ── Founders (portal users) — maps to FounderProfile in noosphere/models.py ─

model Founder {
  id             String       @id @default(cuid())
  organizationId String
  organization   Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  name                    String
  username                String
  email                   String
  passwordHash            String
  // Role ladder — see src/lib/roles.ts for the predicate helpers and
  // the full description of each tier:
  //   admin   → full read + write + can change other founders' roles
  //   founder → full read + write
  //   viewer  → read-only; every write API returns 403 and every UI
  //              affordance for writes is hidden
  // Default "founder" preserves prior behaviour: anyone added via
  // scripts/add-founder.ts is read+write unless explicitly seeded
  // with ADD_FOUNDER_ROLE=viewer or =admin. Validation lives at the
  // application layer; the column stays TEXT so adding a future tier
  // is a docstring + helper change, not a migration.
  role                    String    @default("founder") // admin | founder | viewer
  bio                     String?
  displayName             String?
  roleTitle               String?
  publicUrl               String?
  avatar                  String?
  accountNudgeDismissedAt DateTime?

  /// Maps to FounderProfile.id in Noosphere
  noosphereId String?

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  sessions                   Session[]
  uploads                    Upload[]
  auditEvents                AuditEvent[]
  deletionRequests           DeletionRequest[]
  attributedConclusions      Conclusion[]                @relation("ConclusionFounder")
  researchSuggestions        ResearchSuggestion[]
  reviewResolutions          ReviewItem[]                @relation("ReviewResolver")
  publicationReviews         PublicationReview[]         @relation("PublicationReviewer")
  recalibrationOverrides     RecalibrationOverride[]
  apiKeys                    ApiKey[]
  conclusionDeletionRequests ConclusionDeletionRequest[]
  dashboardDismissals        DashboardDismissal[]
  resolvedContradictions     Contradiction[]             @relation("ContradictionResolver")
  revisionEvents             RevisionEvent[]
  publicReplies              PublicReply[]               @relation("PublicReplyFounder")
  attentionActions           AttentionAction[]

  /// Opt-in flag for the daily morning digest email summarising open
  /// high-severity attention items. Default `false` — silent until the
  /// founder explicitly opts in. See `src/lib/dailyDigestEmail.ts`.
  dailyDigestOptIn Boolean @default(false)

  @@unique([organizationId, email])
  @@unique([organizationId, username])
  @@index([organizationId])
}

/// Browser session (server-side row; cookie carries signed opaque token)
model Session {
  id             String   @id @default(cuid())
  organizationId String
  founderId      String
  token          String   @unique
  expiresAt      DateTime
  createdAt      DateTime @default(now())

  founder      Founder      @relation(fields: [founderId], references: [id], onDelete: Cascade)
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([founderId])
}

// ── Uploads ────────────────────────────────────────────────────────────────

model Upload {
  id             String @id @default(cuid())
  organizationId String
  founderId      String

  title            String
  description      String?
  sourceType       String   @default("written") // written | annotation | external | transcript
  originalName     String
  mimeType         String
  filePath         String
  fileSize         Int
  textContent      String?
  blurb            String?
  // Status ladder (see src/lib/uploadStatus.ts for the canonical
  // vocabulary + UI labels). `pending | processing | ingested | failed`
  // are load-bearing strings from the init migration; `extracting` and
  // `awaiting_ingest` were added alongside the Wave-1 audio/PDF
  // extractors so founders can see which stage of the pipeline a row is
  // in (Whisper/pypdf vs. claim extraction) instead of a single opaque
  // "processing".
  status           String   @default("pending") // pending | extracting | awaiting_ingest | processing | ingested | failed
  processLog       String   @default("") // streamed CLI stdout/stderr
  claimsCount      Int?
  methodCount      Int?
  substCount       Int?
  principleCount   Int?
  errorMessage     String?
  // How the text was obtained for this upload, set by the noosphere
  // extractor dispatcher on success. Free-form string — e.g.
  // "passthrough", "faster-whisper", "openai-whisper-1", "pypdf",
  // "ocrmypdf". Rendered in the dashboard detail row so the founder
  // knows whether a transcript/PDF extract was reliable.
  extractionMethod String?
  createdAt        DateTime @default(now())
  updatedAt        DateTime @updatedAt

  // ── Public blog fields ─────────────────────────────────────────────
  // An Upload becomes a public blog post when `publishedAt IS NOT NULL`.
  // Default is null → the upload remains a private founder artifact.
  // `slug` is the URL-safe identifier used for `/post/:slug`; it's
  // generated from `title` at publish time and guaranteed unique across
  // the whole table (not per-org — the blog is a single public surface).
  // `blogExcerpt` is the card/list summary shown on the index; if null
  // we derive one from the first ~280 chars of `textContent`.
  // `authorBio` lets the founder override the displayed byline (e.g.
  // for guest posts or co-authored work); otherwise we show
  // Founder.name.
  publishedAt DateTime?
  slug        String?   @unique
  blogExcerpt String?
  authorBio   String?

  // ── Soft delete ────────────────────────────────────────────────────
  // `deletedAt` is the single source of truth for "this upload has
  // been removed". Every query that surfaces uploads to the UI must
  // filter by `deletedAt IS NULL`; we keep the row around so the audit
  // trail (AuditEvent pointing at this upload) stays intact, and so a
  // DB-level restore is possible if a deletion turns out to be a
  // mistake. Only the uploader can set this directly; peers must go
  // through a DeletionRequest, which the owner accepts (setting
  // `deletedAt=now`) or declines.
  deletedAt DateTime?

  // ── Visibility inside the firm ─────────────────────────────────────
  // Three-level visibility ladder. Every value still lets Noosphere
  // run ingestion — conclusions, contradictions, open questions, and
  // research suggestions are always extracted. The levels only
  // control *who reads the upload's metadata and contents*.
  //
  // "org"          → visible to every founder in the organization AND
  //                   eligible for blog publication. The default;
  //                   library, dashboard, peer deletion requests, and
  //                   the blog's publishAsPost toggle all apply.
  //
  // "semi-private" → visible to every founder in the organization,
  //                   but never publishable to the public blog. The
  //                   intermediate level, for material the firm wants
  //                   to discuss internally but that must never leak
  //                   outside. /api/publish rejects the flip; the
  //                   public blog index + /post/[slug] both filter
  //                   it out; /library and /dashboard render it with
  //                   a "semi-private" badge so peers know the
  //                   constraint.
  //
  // "private"      → only the uploader can see the row anywhere in
  //                   the UI; Noosphere still ingests it so the owner
  //                   gets their own conclusions/contradictions, but
  //                   nobody else can see the file, read it, or open
  //                   a deletion request against it. Blog-publishing
  //                   a private upload is rejected at the API layer
  //                   — flip visibility first.
  //
  // Column stays TEXT with default "org" so no migration is needed
  // when new levels are introduced; validation happens at the API
  // layer.
  visibility String @default("org")

  // ── Podcast / audio playback ───────────────────────────────────────
  // When an audio upload is stored in a public CDN-addressable
  // location (Supabase Storage in our case), we persist the public
  // URL here so /post/[slug] can render a <audio controls> player
  // alongside the transcript. `audioDurationSec` is optional
  // metadata derived from ffprobe / client-side duration detection
  // when available; the UI falls back to the player's own duration
  // readout if it's null. Both fields are null for non-audio rows

"""CLI commands for the Method Registry subsystem."""

from __future__ import annotations

import json
from datetime import datetime, timezone
from typing import Optional

import click
from rich.console import Console
from rich.table import Table

console = Console()


def _get_store():
    from noosphere.cli import get_orchestrator
    return get_orchestrator(None).store


def _render(obj, as_json: bool) -> None:
    if as_json:
        click.echo(json.dumps(obj, indent=2, default=str))


@click.group("methods")
def cli() -> None:
    """Method registry: list, inspect, run, and diff registered methods."""


@cli.command("list")
@click.option("--status", "status_filter", type=str, default=None,
              help="Filter by status (experimental, active, deprecated, retired)")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def list_methods(status_filter: Optional[str], as_json: bool) -> None:
    """List all registered methods."""
    from noosphere.methods import REGISTRY

    methods = REGISTRY.list(status_filter=status_filter)
    if as_json:
        _render([{"name": m.name, "version": m.version, "status": m.status,
                  "type": m.method_type.value, "description": m.description}
                 for m in methods], True)
        return
    if not methods:
        console.print("[yellow]No methods registered.[/yellow]")
        return
    table = Table(title="Registered Methods", show_header=True)
    table.add_column("Name", style="cyan")
    table.add_column("Version")
    table.add_column("Status")
    table.add_column("Type")
    table.add_column("Description", max_width=50)
    for m in methods:
        table.add_row(m.name, m.version, m.status, m.method_type.value,
                      m.description[:50])
    console.print(table)


@cli.command("show")
@click.argument("ref")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def show_method(ref: str, as_json: bool) -> None:
    """Show details of a method. REF is name or name@version."""
    from noosphere.methods import REGISTRY

    name, version = (ref.split("@", 1) + ["latest"])[:2]
    method, _fn = REGISTRY.get(name, version=version)
    if as_json:
        _render(method.model_dump(), True)
        return
    table = Table(title=f"Method: {method.name}@{method.version}", show_header=False)
    for field in ("method_id", "name", "version", "method_type", "status",
                  "owner", "description", "rationale"):
        val = getattr(method, field)
        table.add_row(field, str(val) if not hasattr(val, "value") else val.value)
    table.add_row("preconditions", ", ".join(method.preconditions) or "—")
    table.add_row("postconditions", ", ".join(method.postconditions) or "—")
    console.print(table)

"""Plugin loader for CLI command modules.

Every Python module in this package that exposes a top-level Click group
named ``cli`` is automatically discovered and attached to the root CLI
group.
"""

from __future__ import annotations

import importlib
import pkgutil
import sys
import types
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    import click


def register_commands(root_cli: click.Group) -> None:
    """Import every sibling module and attach its ``cli`` group to *root_cli*."""
    _install_rich_fallback_if_needed()
    package = importlib.import_module(__name__)
    for _importer, modname, _ispkg in pkgutil.iter_modules(package.__path__):
        mod = importlib.import_module(f"{__name__}.{modname}")
        group = getattr(mod, "cli", None)
        if group is not None:
            root_cli.add_command(group)


def _install_rich_fallback_if_needed() -> None:
    try:
        import rich  # noqa: F401
        return
    except ImportError:
        pass

    class Console:
        def print(self, *args, **_kwargs) -> None:
            print(" ".join(str(arg) for arg in args))

    class Table:
        def __init__(self, title: str = "", show_header: bool = True, **_kwargs) -> None:
            self.title = title
            self.rows: list[tuple[str, ...]] = []

        def add_column(self, *_args, **_kwargs) -> None:
            return None

        def add_row(self, *args, **_kwargs) -> None:
            self.rows.append(tuple(str(arg) for arg in args))

        def __str__(self) -> str:
            lines = [self.title] if self.title else []
            lines.extend(" | ".join(row) for row in self.rows)
            return "\n".join(lines)

    rich_mod = types.ModuleType("rich")
    console_mod = types.ModuleType("rich.console")
    table_mod = types.ModuleType("rich.table")
    console_mod.Console = Console
    table_mod.Table = Table
    rich_mod.console = console_mod
    rich_mod.table = table_mod
    sys.modules.setdefault("rich", rich_mod)
    sys.modules.setdefault("rich.console", console_mod)
    sys.modules.setdefault("rich.table", table_mod)

class Conclusion(BaseModel):
    """A reasoned conclusion drawn from principles and claims."""

    id: str = Field(default_factory=lambda: str(uuid.uuid4()))
    text: str
    reasoning: str = ""
    rationale: str = ""
    kind: ConclusionKind = ConclusionKind.FIRM
    confidence_tier: ConfidenceTier = ConfidenceTier.MODERATE
    principles_used: list[str] = []
    claims_used: list[str] = []
    supporting_principle_ids: list[str] = Field(default_factory=list)
    evidence_chain_claim_ids: list[str] = Field(default_factory=list)
    dissent_claim_ids: list[str] = Field(default_factory=list)
    confidence: float = 0.0
    disciplines: list[Discipline] = []
    created_at: datetime = Field(default_factory=datetime.now)
    updated_at: datetime = Field(default_factory=datetime.now)
    superseded_at: Optional[datetime] = None
    # Round 3 additions
    freshness: Freshness = Freshness.FRESH
    last_validated_at: Optional[datetime] = None

    @model_validator(mode="after")
    def _sync_legacy_aliases(self) -> Conclusion:
        if not self.rationale and self.reasoning:
            self.rationale = self.reasoning
        if not self.reasoning and self.rationale:
            self.reasoning = self.rationale
        if not self.supporting_principle_ids and self.principles_used:
            self.supporting_principle_ids = list(self.principles_used)
        if not self.principles_used and self.supporting_principle_ids:
            self.principles_used = list(self.supporting_principle_ids)
        if not self.evidence_chain_claim_ids and self.claims_used:
            self.evidence_chain_claim_ids = list(self.claims_used)
        if not self.claims_used and self.evidence_chain_claim_ids:
            self.claims_used = list(self.evidence_chain_claim_ids)
        return self


SIGNIFICANCE_WEIGHTS: dict[str, float] = {
    "impressions": 0.4,
    "retweets": 0.3,
    "likes": 0.2,
    "replies": 0.05,
    "quotes_bookmarks": 0.1,
}
# These weights deliberately privilege impressions as reach, retweets as
# endorsement-led amplification, likes as broad reaction volume, replies as
# public conversational activity, and quotes/bookmarks as deeper engagement
# signals; the resulting log-sum is monotonic while dampening raw-count
# outliers until prompt 03 adds ranking.


def _metric_count(value: Any) -> int:
    if value is None:
        return 0
    try:
        number = float(value)
    except (TypeError, ValueError):
        return 0
    if not math.isfinite(number) or number < 0:
        return 0
    return int(number)


class XSignificanceMetrics(BaseModel):
    model_config = ConfigDict(extra="ignore")

    like_count: int = 0
    retweet_count: int = 0
    reply_count: int = 0
    quote_count: int = 0
    bookmark_count: int = 0
    impression_count: int = 0
    significance_score: float = 0.0

    @field_validator(
        "like_count",
        "retweet_count",
        "reply_count",
        "quote_count",
        "bookmark_count",
        "impression_count",
        mode="before",
    )
    @classmethod
    def _coerce_counts(cls, value: Any) -> int:
        return _metric_count(value)

    @field_validator("significance_score", mode="before")
    @classmethod
    def _coerce_score(cls, value: Any) -> float:
        try:
            score = float(value)
        except (TypeError, ValueError):
            return 0.0
        return score if math.isfinite(score) else 0.0

    @model_validator(mode="after")

import type { Metadata } from "next";
import Link from "next/link";

import MethodologyIndexTable from "@/components/MethodologyIndexTable";
import PublicHeader from "@/components/PublicHeader";
import { getFounder } from "@/lib/auth";
import { buildMethodologyManifest } from "@/lib/methodologyManifest";

export const metadata: Metadata = {
  title: "Methodology",
  description:
    "Theseus's methodology explorer: methods, calibration, drift, composition, and failure modes — the firm's reasoning published for inspection and reuse.",
  openGraph: {
    title: "Theseus Methodology Explorer",
    description:
      "The reusable part of inquiry. Inspect Theseus's methods, their calibration, and where they have failed.",
    type: "website",
  },
};

export const dynamic = "force-dynamic";

/**
 * Public methodology directory.
 *
 * Server-rendered: an outsider's first paint is the full method index,
 * not a loading state. Client-side hydration only adds search,
 * sorting, and filtering — the table content itself is in the HTML.
 */
export default async function MethodologyPage() {
  const founder = await getFounder();
  const manifest = await buildMethodologyManifest();

  return (
    <>
      <PublicHeader authed={Boolean(founder)} />
      <a href="#methodology-index" className="public-skip-link">
        Skip to method index
      </a>
      <style>{skipLinkCss}</style>
      <main id="methodology-main" className="public-container public-methodology-page">
        <section className="public-section" aria-labelledby="methodology-hero-title">
          <h1 id="methodology-hero-title" className="public-title">
            The reusable part of inquiry
          </h1>
          <p className="public-lede">
            Theseus publishes its conclusions, but the more durable public
            object is the discipline that produced them. The meta-method is
            five working criteria — Progressivity, Severity, Aim-Method Fit,
            Compressibility, Domain Sensitivity — applied to each method so a
            reader can see what the method is, how it has calibrated, where
            it composes with other methods, and where it has failed. Nothing
            here is private; everything is filtered for public visibility
            before it reaches this page.
          </p>
          <p style={{ marginTop: "1.25rem" }}>
            <Link
              href="#methodology-index"
              className="mono"
              style={{
                display: "inline-block",
                padding: "0.55rem 1.1rem",
                border: "1px solid var(--amber, #d4a017)",
                color: "var(--amber, #d4a017)",
                textDecoration: "none",
                fontSize: "0.68rem",
                letterSpacing: "0.22em",
                textTransform: "uppercase",
              }}
            >
              Explore the methods →
            </Link>
          </p>
        </section>

        <section className="public-section" aria-labelledby="methodology-routes-title">
          <h2 id="methodology-routes-title">Where to start</h2>
          <ul
            style={{
              listStyle: "none",
              padding: 0,
              margin: 0,
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
              gap: "0.9rem",
            }}
          >
            <RouteCard
              href="/methodology/criteria"
              label="Five-criterion rubric"
              body="The exact rubric the firm uses when scoring its own methods (the MQS)."
            />
            <RouteCard
              href="/methodology/composition"
              label="Composition map"
              body="How the methods build on each other — extractor → judge → synthesis."
            />
            <RouteCard
              href="#methodology-failure-modes"
              label="Public failure modes"
              body="Catalog entries the firm is willing to publish about how its methods break."
            />
            <RouteCard
              href="/api/public/methodology/manifest"
              label="Manifest API"
              body="A single JSON document — the same one this page reads — for outside replication."
            />
          </ul>
        </section>

        <section
          className="public-section"
          id="methodology-index"
          aria-labelledby="methodology-index-title"
        >
          <h2 id="methodology-index-title">Method index</h2>
          <p className="public-muted" style={{ marginTop: 0 }}>
            Sortable. Filterable by domain. Calibration slope is shown only
            for methods whose track record clears the firm's publish gate;
            below that, the cell is left blank instead of dressed up.
          </p>
          <MethodologyIndexTable methods={manifest.methods} />
        </section>

        <section
          className="public-section"
          id="methodology-failure-modes"
          aria-labelledby="methodology-failure-modes-title"
        >
          <h2 id="methodology-failure-modes-title">Public failure modes</h2>
          <p className="public-muted">
            {manifest.publicFailureModes.length} entries published across all
            methods. Each method's full catalog is reachable from its
            page; the firm holds private entries until the framing matures.
          </p>
        </section>

        <section className="public-section" aria-labelledby="methodology-policy-title">
          <h2 id="methodology-policy-title">Public boundaries</h2>
          <div className="public-card public-method-note" role="note">
            <p>
              The explorer is deliberately incomplete in one respect: it does
              not expose raw deliberation, private transcript text, or
              unreviewed chain-of-thought. It exposes the method at the level
              needed for critique and reuse. Material revisions create a new
              immutable snapshot row so prior URLs do not rot.
            </p>
          </div>
        </section>
      </main>
    </>
  );
}

function RouteCard({
  href,
  label,
  body,
}: {
  href: string;
  label: string;
  body: string;
}) {
