// ── Principles (cross-domain distillations) ────────────────────────────────
//
// Output of the corpus-level distillation pipeline. A Principle is a
// single-sentence claim the firm is willing to defend, derived from
// the embedding-space neighborhood of its conclusions.
//
// Lifecycle:
//   draft           — surfaced by the pipeline; awaiting founder triage
//   accepted        — founder approved (with edits); shown publicly when
//                     `publicVisible = true`
//   rejected        — founder declined (`triageReason` records why)
//   merged          — folded into another principle (`mergedIntoId`)
//   needs_rereview  — the underlying cluster has shifted; founder must
//                     re-validate before it stays accepted
//
// Conviction scoring is conservative: a single high-centrality
// conclusion does not produce conviction; convergence across domains
// does. See noosphere/distillation/principle_distillation.py.
model Principle {
  id             String @id @default(cuid())
  organizationId String

  text        String
  /// JSON string[] of domain tags the firm is willing to attach.
  /// Public principles must declare their domain; surfaces refuse to
  /// publish if this is empty.
  domainsJson String @default("[]")

  /// JSON string[] of Conclusion ids in the cluster that produced
  /// the principle. The full cluster — not just the LLM-cited subset.
  clusterConclusionIds String @default("[]")
  /// JSON string[] of Conclusion ids the LLM explicitly cited.
  citedConclusionIds   String @default("[]")

  /// status ladder — see model docstring.
  status String @default("draft")
  /// draft | accepted | rejected | merged | needs_rereview source.
  triageReason String @default("")
  /// Set on `merged`: target principle id this row was folded into.
  mergedIntoId String?

  /// Conservative score in [0, 1]. Conviction-weighted ordering on the
  /// public methodology page reads this column.
  convictionScore Float @default(0.0)
  /// Distinct domains in the cluster — proxy for cross-domain
  /// convergence. Zero unless the cluster spans multiple disciplines.
  domainBreadth   Int   @default(0)
  /// Mean cosine similarity of cluster members to the cluster centroid.
  clusterCentroidSimilarity Float @default(0.0)

  /// Whether the firm is willing to publish this principle on the
  /// public methodology surface. Acceptance does not imply publication.
  publicVisible Boolean @default(false)

  /// The diff reason emitted by `redistill` when an existing principle's
  /// cluster has shifted: cluster_grew | cluster_shrunk |
  /// cluster_added_and_retracted | cluster_dissolved. Cleared when the
  /// founder re-accepts.
  driftReason String?

  /// Founder who last accepted/edited this row.
  reviewedByFounderId String?

  createdAt   DateTime  @default(now())
  updatedAt   DateTime  @updatedAt
  reviewedAt  DateTime?
  publishedAt DateTime?

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([organizationId, status])
  @@index([organizationId, publicVisible])
}
